import { useEffect, useState } from 'react';
import { useKeyboardInset } from '@/hooks/useKeyboardInset';

export function AdaptiveSheet({ open, onClose, children }: { open: boolean; onClose: () => void; children: React.ReactNode }) {
  useKeyboardInset();
  const [keyboardOpen, setKeyboardOpen] = useState(false);

  useEffect(() => {
    if (!('visualViewport' in window) || !window.visualViewport) return;
    const vv = window.visualViewport;
    const check = () => setKeyboardOpen(vv.height < window.innerHeight - 50);
    check();
    vv.addEventListener('resize', check);
    return () => vv.removeEventListener('resize', check);
  }, [open]);

  if (!open) return null;
  return (
    <>
      <div className="fixed inset-0 z-50 bg-black/50" onClick={onClose} />
      <div
        role="dialog"
        aria-modal="true"
        className={`
          fixed inset-x-0 bottom-0 z-50 bg-white shadow-2xl overflow-hidden flex flex-col
          transition-[height,border-radius]
          ${keyboardOpen ? 'h-dvh rounded-none' : 'max-h-[85dvh] rounded-t-2xl'}
        `}
        style={{
          paddingBottom: keyboardOpen ? 'var(--keyboard-inset, 0px)' : 'env(safe-area-inset-bottom)',
        }}
      >
        <div className="flex-1 overflow-y-auto">{children}</div>
      </div>
    </>
  );
}

