// components/InputAccessoryBar.tsx
import { useEffect, useState, useRef } from 'react';
import { useKeyboardInset } from '@/hooks/useKeyboardInset';

export function InputAccessoryBar({ formRef }: { formRef: React.RefObject<HTMLFormElement> }) {
  useKeyboardInset();
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (!('visualViewport' in window) || !window.visualViewport) return;
    const vv = window.visualViewport;
    const check = () => setVisible(vv.height < window.innerHeight - 50);
    vv.addEventListener('resize', check);
    return () => vv.removeEventListener('resize', check);
  }, []);

  const navigate = (direction: 1 | -1) => {
    if (!formRef.current) return;
    const inputs = Array.from(formRef.current.querySelectorAll<HTMLInputElement>('input, textarea, select'));
    const idx = inputs.findIndex((i) => i === document.activeElement);
    const next = inputs[idx + direction];
    next?.focus();
  };

  const done = () => (document.activeElement as HTMLElement)?.blur();

  if (!visible) return null;
  return (
    <div
      className="fixed inset-x-0 z-40 flex items-center justify-between border-t bg-neutral-100 px-3"
      style={{
        bottom: 'var(--keyboard-inset, 0px)',
        height: '44px',
      }}
    >
      <div className="flex">
        <button type="button" onClick={() => navigate(-1)} aria-label="Previous field" className="flex h-11 min-w-11 items-center px-3 text-blue-600">‹</button>
        <button type="button" onClick={() => navigate(1)} aria-label="Next field" className="flex h-11 min-w-11 items-center px-3 text-blue-600">›</button>
      </div>
      <button type="button" onClick={done} className="min-h-11 px-3 font-semibold text-blue-600">Done</button>
    </div>
  );
}

