// components/OtpInput.tsx
import { useRef, useState } from 'react';

export function OtpInput({ length = 6, onComplete }: { length?: number; onComplete: (code: string) => void }) {
  const [digits, setDigits] = useState<string[]>(Array(length).fill(''));
  const refs = useRef<(HTMLInputElement | null)[]>([]);

  const setAt = (i: number, val: string) => {
    const cleaned = val.replace(/\D/g, '');
    if (cleaned.length > 1) {
      // Paste — distribute
      const next = [...digits];
      for (let j = 0; j < cleaned.length && i + j < length; j++) next[i + j] = cleaned[j];
      setDigits(next);
      const lastIdx = Math.min(i + cleaned.length, length - 1);
      refs.current[lastIdx]?.focus();
      if (next.every((d) => d)) onComplete(next.join(''));
      return;
    }
    const next = [...digits];
    next[i] = cleaned;
    setDigits(next);
    if (cleaned && i < length - 1) refs.current[i + 1]?.focus();
    if (next.every((d) => d)) onComplete(next.join(''));
  };

  const onKeyDown = (i: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !digits[i] && i > 0) refs.current[i - 1]?.focus();
    if (e.key === 'ArrowLeft' && i > 0) refs.current[i - 1]?.focus();
    if (e.key === 'ArrowRight' && i < length - 1) refs.current[i + 1]?.focus();
  };

  return (
    <div role="group" aria-label="Verification code" className="flex justify-center gap-2">
      {digits.map((d, i) => (
        <input
          key={i}
          ref={(el) => (refs.current[i] = el)}
          type="text"
          inputMode="numeric"
          pattern="\d*"
          maxLength={length}
          autoComplete={i === 0 ? 'one-time-code' : 'off'}
          value={d}
          onChange={(e) => setAt(i, e.target.value)}
          onKeyDown={(e) => onKeyDown(i, e)}
          onFocus={(e) => e.target.select()}
          aria-label={`Digit ${i + 1}`}
          className="
            h-12 w-10 sm:h-14 sm:w-12
            text-center text-xl tabular-nums
            rounded border-2 border-neutral-300 focus:border-blue-500 outline-none
          "
        />
      ))}
    </div>
  );
}

