// components/Pagination.tsx
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { ChevronLeft, ChevronRight } from 'lucide-react';

export function Pagination({ page, totalPages, onPageChange, onLoadMore, hasMore }: {
  page: number;
  totalPages: number;
  onPageChange: (p: number) => void;
  onLoadMore?: () => void;
  hasMore?: boolean;
}) {
  const bp = useBreakpoint();

  if (bp === 'mobile') {
    return hasMore ? (
      <button
        type="button"
        onClick={onLoadMore}
        className="w-full min-h-12 rounded-lg border bg-white px-4 font-medium hover:bg-neutral-50"
      >Load more ({totalPages - page} pages left)</button>
    ) : null;
  }

  const pages: (number | '...')[] = [];
  if (totalPages <= 7) {
    for (let i = 1; i <= totalPages; i++) pages.push(i);
  } else {
    pages.push(1);
    if (page > 3) pages.push('...');
    for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) pages.push(i);
    if (page < totalPages - 2) pages.push('...');
    pages.push(totalPages);
  }

  return (
    <nav aria-label="Pagination" className="flex items-center justify-center gap-1">
      <button
        type="button"
        onClick={() => onPageChange(page - 1)}
        disabled={page === 1}
        aria-label="Previous page"
        className="flex h-10 min-w-10 items-center justify-center rounded border bg-white disabled:opacity-50"
      ><ChevronLeft className="h-4 w-4" /></button>
      {pages.map((p, i) => p === '...' ? (
        <span key={`e-${i}`} className="px-2 text-neutral-400" aria-hidden>…</span>
      ) : (
        <button
          key={p}
          type="button"
          onClick={() => onPageChange(p)}
          aria-current={p === page ? 'page' : undefined}
          aria-label={`Page ${p}`}
          className={`
            flex h-10 min-w-10 items-center justify-center rounded border
            ${p === page ? 'border-blue-500 bg-blue-50 text-blue-900 font-medium' : 'bg-white'}
          `}
        >{p}</button>
      ))}
      <button
        type="button"
        onClick={() => onPageChange(page + 1)}
        disabled={page === totalPages}
        aria-label="Next page"
        className="flex h-10 min-w-10 items-center justify-center rounded border bg-white disabled:opacity-50"
      ><ChevronRight className="h-4 w-4" /></button>
    </nav>
  );
}

