// Design checklist for zoom-friendly layouts
// 1. Container max-widths in rem, not px
// 2. Font sizes via clamp() with rem clamp bounds
// 3. Spacing via clamp(rem-based)
// 4. Test at viewport width 320px AT 100% zoom (= simulating 640px at 200% zoom)

/* globals.css - resilient defaults */
html { font-size: 100%; /* honor user setting */ }

/* Container that scales with zoom */
.container { max-width: 75rem; /* not 1200px */ margin-inline: auto; padding-inline: clamp(1rem, 4vw, 2rem); }

/* Buttons that scale */
.btn { min-height: 2.75rem; /* 44px at default; scales with rem */ padding-inline: 1rem; }

/* Forms that scale */
input { min-height: 2.75rem; font-size: 1rem; }

// Tests:
