// hooks/useVirtualKeyboard.ts
import { useEffect, useState } from 'react';

export function useVirtualKeyboard() {
  const [inset, setInset] = useState(0);

  useEffect(() => {
    // @ts-expect-error — virtualKeyboard not in TS lib yet
    const vk = navigator.virtualKeyboard;

    if (vk) {
      vk.overlaysContent = true;
      const onGeometry = () => setInset(vk.boundingRect.height);
      vk.addEventListener('geometrychange', onGeometry);
      return () => vk.removeEventListener('geometrychange', onGeometry);
    }

    // Fallback: visualViewport
    if ('visualViewport' in window && window.visualViewport) {
      const vv = window.visualViewport;
      const onResize = () => setInset(Math.max(0, window.innerHeight - vv.height));
      vv.addEventListener('resize', onResize);
      return () => vv.removeEventListener('resize', onResize);
    }
  }, []);

  return inset;
}

