// components/SwipeableListItem.tsx
import { useState } from 'react';

export function SwipeableListItem({ children, onDelete }: { children: React.ReactNode; onDelete: () => void }) {
  const [offset, setOffset] = useState(0);
  const [revealed, setRevealed] = useState(false);

  const onPointerDown = (e: React.PointerEvent) => {
    if (e.pointerType !== 'touch') return;
    // Ignore swipes starting near edges (browser back gesture)
    if (e.clientX < 20 || e.clientX > window.innerWidth - 20) return;

    const startX = e.clientX;
    const startOffset = offset;

    const onMove = (ev: PointerEvent) => {
      const dx = ev.clientX - startX;
      const next = Math.max(-100, Math.min(0, startOffset + dx));
      setOffset(next);
    };

    const onUp = () => {
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
      if (offset < -50) { setOffset(-100); setRevealed(true); }
      else { setOffset(0); setRevealed(false); }
    };

    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  };

  return (
    <li className="relative overflow-hidden bg-white" style={{ touchAction: 'pan-y' }}>
      <div
        className="relative flex items-center min-h-14 px-4 transition-transform"
        style={{ transform: `translateX(${offset}px)` }}
        onPointerDown={onPointerDown}
      >
        {children}
      </div>
      {revealed && (
        <button
          type="button"
          onClick={onDelete}
          className="absolute right-0 top-0 h-full w-[100px] bg-red-500 text-white font-medium"
        >Delete</button>
      )}
    </li>
  );
}

// components/KeyboardSafeModal.tsx — only relevant logic
import { useEffect } from 'react';
import { useKeyboardInset } from '@/hooks/useKeyboardInset';

export function KeyboardSafeModal({ open, onClose, children }: { open: boolean; onClose: () => void; children: React.ReactNode }) {
  useKeyboardInset();

  // Do NOT close on visualViewport changes — keyboard transitions don't dismiss modal
  // Close only on:
  // 1. Explicit backdrop click
  // 2. Close button click
  // 3. Escape key

  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => e.key === 'Escape' && onClose();
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  const handleBackdropClick = (e: React.MouseEvent) => {
    // Only close if user clicked backdrop directly, not bubbled from content
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/50"
      onClick={handleBackdropClick}
    >
      <div
        role="dialog"
        aria-modal="true"
        className="w-full sm:max-w-md bg-white rounded-t-2xl sm:rounded-xl shadow-2xl overflow-hidden"
        style={{
          transform: 'translateY(calc(-1 * var(--keyboard-inset, 0px)))',
          transition: 'transform 200ms',
          paddingBottom: 'max(0px, env(safe-area-inset-bottom))',
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {children}
      </div>
    </div>
  );
}

