export function PreviewableLink({ href, label, preview }: { href: string; label: string; preview: React.ReactNode }) {
  const canHover = useMediaQuery('(hover: hover) and (pointer: fine)', false);
  const [showPreview, setShowPreview] = useState(false);

  return (
    <span className="relative inline-block">
      <a
        href={href}
        onMouseEnter={canHover ? () => setShowPreview(true) : undefined}
        onMouseLeave={canHover ? () => setShowPreview(false) : undefined}
        onFocus={canHover ? () => setShowPreview(true) : undefined}
        onBlur={canHover ? () => setShowPreview(false) : undefined}
        className="text-blue-600 underline hover:text-blue-800"
      >{label}</a>
      {canHover && showPreview && (
        <div
          role="tooltip"
          className="absolute left-0 top-full z-30 mt-2 w-80 rounded-lg border bg-white p-3 shadow-xl"
        >{preview}</div>
      )}
    </span>
  );
}

