// components/SearchableSelect.tsx
import { useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';
import { ChevronDown } from 'lucide-react';

type Option = { value: string; label: string };

export function SearchableSelect({ options, value, onChange, label }: { options: Option[]; value: string; onChange: (v: string) => void; label: string }) {
  const isTouch = useMediaQuery('(pointer: coarse)', true);

  if (isTouch) {
    return (
      <label className="block">
        <span className="text-sm font-medium">{label}</span>
        <select
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="mt-1 block w-full min-h-11 rounded border bg-white px-3 text-base"
        >
          {options.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
        </select>
      </label>
    );
  }

  return <DesktopCombobox options={options} value={value} onChange={onChange} label={label} />;
}

function DesktopCombobox({ options, value, onChange, label }: any) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const filtered = options.filter((o: Option) => o.label.toLowerCase().includes(query.toLowerCase()));
  const current = options.find((o: Option) => o.value === value);

  return (
    <div className="relative">
      <label className="block">
        <span className="text-sm font-medium">{label}</span>
        <button
          type="button"
          onClick={() => setOpen(true)}
          className="mt-1 flex w-full min-h-11 items-center justify-between rounded border bg-white px-3 text-left"
          aria-haspopup="listbox"
          aria-expanded={open}
        >
          <span>{current?.label || 'Select...'}</span>
          <ChevronDown className="h-4 w-4 text-neutral-500" />
        </button>
      </label>
      {open && (
        <div className="absolute left-0 right-0 top-full z-30 mt-1 max-h-64 overflow-hidden rounded border bg-white shadow-lg">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search"
            autoFocus
            className="w-full border-b px-3 py-2 outline-none"
          />
          <ul role="listbox" className="max-h-48 overflow-y-auto">
            {filtered.map((o: Option) => (
              <li key={o.value}>
                <button
                  type="button"
                  role="option"
                  aria-selected={value === o.value}
                  onClick={() => { onChange(o.value); setOpen(false); setQuery(''); }}
                  className="block w-full px-3 py-1.5 text-left hover:bg-neutral-50"
                >{o.label}</button>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

// components/AdaptiveAudioPlayer.tsx
'use client';
import { useRef, useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { Play, Pause, SkipForward, SkipBack, Volume2 } from 'lucide-react';

export function AdaptiveAudioPlayer({ track }: { track: { src: string; title: string; artist: string; cover: string } }) {
  const bp = useBreakpoint();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [playing, setPlaying] = useState(false);

  const togglePlay = () => {
    if (playing) audioRef.current?.pause();
    else audioRef.current?.play();
  };

  if (bp === 'mobile') {
    return (
      <div
        className="fixed inset-x-0 bottom-0 z-30 border-t bg-white"
        style={{ paddingBottom: 'env(safe-area-inset-bottom)' }}
      >
        <audio ref={audioRef} src={track.src} onPlay={() => setPlaying(true)} onPause={() => setPlaying(false)} />
        <div className="flex items-center gap-3 px-3 py-2">
          <img src={track.cover} alt="" className="h-10 w-10 rounded" />
          <div className="flex-1 min-w-0">
            <div className="truncate text-sm font-medium">{track.title}</div>
            <div className="truncate text-xs text-neutral-500">{track.artist}</div>
          </div>
          <button onClick={togglePlay} aria-label={playing ? 'Pause' : 'Play'} className="flex h-11 w-11 items-center justify-center rounded-full bg-black text-white">
            {playing ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5" />}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-x-0 bottom-0 z-30 border-t bg-white px-6 py-3">
      <audio ref={audioRef} src={track.src} onPlay={() => setPlaying(true)} onPause={() => setPlaying(false)} />
      <div className="flex items-center gap-4">
        <img src={track.cover} alt="" className="h-14 w-14 rounded" />
        <div className="min-w-0 w-48">
          <div className="truncate font-medium">{track.title}</div>
          <div className="truncate text-sm text-neutral-500">{track.artist}</div>
        </div>
        <div className="flex flex-1 flex-col items-center gap-1">
          <div className="flex items-center gap-3">
            <button aria-label="Previous" className="text-neutral-500"><SkipBack className="h-5 w-5" /></button>
            <button onClick={togglePlay} aria-label={playing ? 'Pause' : 'Play'} className="flex h-10 w-10 items-center justify-center rounded-full bg-black text-white">
              {playing ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5" />}
            </button>
            <button aria-label="Next" className="text-neutral-500"><SkipForward className="h-5 w-5" /></button>
          </div>
          <input type="range" aria-label="Scrub" className="w-full max-w-md" />
        </div>
        <div className="flex items-center gap-2 w-32">
          <Volume2 className="h-4 w-4 text-neutral-500" />
          <input type="range" aria-label="Volume" className="flex-1" />
        </div>
      </div>
    </div>
  );
}

// components/ScrollableTabs.tsx
import { useRef, useEffect } from 'react';

type Tab = { id: string; label: string };

export function ScrollableTabs({ tabs, active, onChange }: { tabs: Tab[]; active: string; onChange: (id: string) => void }) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Auto-scroll active tab into view
  useEffect(() => {
    const el = containerRef.current?.querySelector<HTMLElement>(`[data-tab-id="${active}"]`);
    el?.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
  }, [active]);

  return (
    <div className="relative">
      <div
        ref={containerRef}
        role="tablist"
        className="
          flex overflow-x-auto scroll-smooth
          [&::-webkit-scrollbar]:hidden [scrollbar-width:none]
          snap-x px-4
        "
      >
        {tabs.map((t) => (
          <button
            key={t.id}
            role="tab"
            data-tab-id={t.id}
            aria-selected={active === t.id}
            onClick={() => onChange(t.id)}
            className={`
              flex-none snap-start whitespace-nowrap
              min-h-11 px-4 text-sm font-medium
              border-b-2
              ${active === t.id ? 'border-blue-500 text-blue-700' : 'border-transparent text-neutral-600'}
            `}
          >{t.label}</button>
        ))}
      </div>
      {/* Gradient indicators */}
      <div className="pointer-events-none absolute left-0 top-0 bottom-0 w-6 bg-gradient-to-r from-white" aria-hidden />
      <div className="pointer-events-none absolute right-0 top-0 bottom-0 w-6 bg-gradient-to-l from-white" aria-hidden />
    </div>
  );
}
